//useState- מאפשר לשמור נתונים מקומיים שמשתנים תוך כדי עבודה
//useEffect- השומר של הקומפוננטה. מאפשר לנו לעמוד על נקודות זמן מסוימות
import React, { useEffect, useState } from 'react';
//useSelector- שולף נתונים מהמחסן הגולבלי (סטור)
//useDispatch- מעדכן את המחסן הגלובלי (סטור)
import { useSelector, useDispatch } from 'react-redux';
//ייבוא פעולות מהרידקס פעולות אלו הם אנשי קשר של השרת
import { getAll, deleteCategory, addCategory, updateCategory } from '../api/categoryApi';
//ייבוא הפעולה שמעדכנת את הסטור של הקטגוריות
import { setCategories } from '../redux/categoryReducer';
//ייבוא קובץ עיצוב
import './category.css';

const Category = () => {
    const dispatch = useDispatch();
    const categories = useSelector((state) => state.category.categories);

    // מצב מקומי לשם ולתיאור (כדי שלא יהיה ריק)
    const [newCategory, setNewCategory] = useState("");
    const [description, setDescription] = useState(""); 
    const [editingId, setEditingId] = useState(null); 

    useEffect(() => {
        if (categories.length === 0) {
            refreshCategories();
        }
    }, []);

    const refreshCategories = async () => {
        const data = await getAll();
        if (data) {
            dispatch(setCategories(data));
        };
    };

    const handleSave = async () => {
        if (!newCategory.trim()) return;

        const categoryData = { 
            categoryName: newCategory,
            description: description // הוספת המלל הנוסף
        };

        if (editingId) {
            await updateCategory(editingId, categoryData);
            setEditingId(null);
        } else {
            await addCategory(categoryData);
        }
        setNewCategory("");
        setDescription("");
        refreshCategories();
    };

    const handleDelete = async (category) => {
        if (window.confirm(`אתה בטוח שאתה רוצה למחוק את ${category.categoryName}?`)) {
            await deleteCategory(category._id);
            refreshCategories();
        }
    };

    const startEditing = (category) => {
        setEditingId(category._id);
        setNewCategory(category.categoryName);
        setDescription(category.description || "");
    };

    return (
        <div className="shop-page-container">
            <div className="category-wrapper">
                <h1 className="shop-title">ניהול קטגוריות</h1>
                
                <div className="category-control-panel">
                    <div className="input-group-modern">
                        <input
                            className="category-input-modern"
                            type="text"
                            value={newCategory}
                            onChange={(e) => setNewCategory(e.target.value)}
                            placeholder="שם הקטגוריה..."
                        />
                        <input
                            className="category-input-modern"
                            type="text"
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            placeholder="תיאור קצר (שלא יהיה ריק...)"
                        />
                        <button className="btn-add-tech" onClick={handleSave}>
                            {editingId ? "שמור שינויים" : "הוסף קטגוריה"}
                        </button>
                    </div>
                </div>

                <div className="categories-slim-list">
                    {categories.map((category) => (
                        <div key={category._id} className="category-slim-card">
                            <div className="category-info">
                                <h3 className="category-name-small">{category.categoryName}</h3>
                                <p className="category-desc-small">{category.description || "אין תיאור זמין כרגע."}</p>
                            </div>
                            <div className="category-actions-row">
                                <button className="btn-edit-small" onClick={() => startEditing(category)}>ערוך</button>
                                <button className="btn-delete-small" onClick={() => handleDelete(category)}>מחק</button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default Category;
